@page "/apply"
@using sv_d618171453f14fae94d54c92e0074f01.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps"
        StepNames="stepNames" OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep @ref="personalInfoStep" Model="personalInfo"
                    OnEmailValidated="ValidateEmail" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries" OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="references" OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep CoverLetter="@coverLetter" CoverLetterChanged="v => coverLetter = v"
                    OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep @ref="reviewStep" Personal="personalInfo" WorkEntries="workEntries"
                    References="references" CoverLetter="@coverLetter"
                    OnEditSection="GoToStep" OnBack="PreviousStep" OnSubmit="SubmitApplication" />
                break;
        }
    </div>
</div>

@code {
    private static readonly IReadOnlyList<string> stepNames = new[]
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private int currentStep;
    private HashSet<int> completedSteps = new();

    // Form state
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    // Component refs
    private PersonalInfoStep? personalInfoStep;
    private ReviewStep? reviewStep;

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
        {
            currentStep = step;
        }
    }

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private async Task ValidateEmail(string? email)
    {
        if (string.IsNullOrWhiteSpace(email))
            return;

        var isValid = await ApplicationService.ValidateEmailAsync(email);
        if (isValid)
        {
            personalInfoStep?.ClearEmailError();
            NextStep();
        }
        else
        {
            personalInfoStep?.SetEmailError("This email address is not valid.");
        }
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        try
        {
            var id = await ApplicationService.SubmitApplicationAsync(application);
            reviewStep?.ShowConfirmation(id);
        }
        catch (Exception ex)
        {
            reviewStep?.ShowError($"Submission failed: {ex.Message}");
        }
    }
}

.step-indicator {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    counter-reset: step;
}

.step-item {
    flex: 1;
    text-align: center;
    position: relative;
}

/* Connector line between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 16px;
    left: 55%;
    right: -45%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background: #198754;
}

.step-item.active:not(:last-child)::after {
    background: linear-gradient(to right, #0d6efd 50%, #dee2e6 50%);
}

.step-content,
.step-button {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    background: none;
    border: none;
    padding: 0;
    width: 100%;
    font: inherit;
    color: inherit;
}

.step-button {
    cursor: pointer;
}

.step-button:hover .step-icon {
    transform: scale(1.1);
}

.step-icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border-radius: 50%;
    font-size: 0.85rem;
    font-weight: 600;
    z-index: 1;
    transition: transform 0.15s;
}

.step-label {
    font-size: 0.75rem;
    white-space: nowrap;
}

/* States */
.step-item.active .step-icon {
    background: #0d6efd;
    color: white;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-icon {
    background: #198754;
    color: white;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.pending .step-icon {
    background: #dee2e6;
    color: #6c757d;
}

.step-item.pending .step-label {
    color: #adb5bd;
}

