        if (completedSteps.Contains(step) || step == currentStep)
        {
            currentStep = step;
        }
    }

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private async Task ValidateEmail(string? email)
    {
        if (string.IsNullOrWhiteSpace(email))
            return;

        var isValid = await ApplicationService.ValidateEmailAsync(email);
        if (isValid)
        {
            personalInfoStep?.ClearEmailError();
            NextStep();
        }
        else
        {
            personalInfoStep?.SetEmailError("This email address is not valid.");
        }
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        try
        {
            var id = await ApplicationService.SubmitApplicationAsync(application);
            reviewStep?.ShowConfirmation(id);
        }
        catch (Exception ex)
        {
            reviewStep?.ShowError($"Submission failed: {ex.Message}");
        }
    }
}

