toolArgs.file_text:
.step-indicator {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    counter-reset: step;
}

.step-item {
    flex: 1;
    text-align: center;
    position: relative;
}

/* Connector line between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 16px;
    left: 55%;
    right: -45%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background: #198754;
}

.step-item.active:not(:last-child)::after {
    background: linear-gradient(to right, #0d6efd 50%, #dee2e6 50%);
}

.step-content,
.step-button {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    background: none;
    border: none;
    padding: 0;
    width: 100%;
    font: inherit;
    color: inherit;
}

.step-button {
    cursor: pointer;
}

.step-button:hover .step-icon {
    transform: scale(1.1);
}

.step-icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border-radius: 50%;
    font-size: 0.85rem;
    font-weight: 600;
    z-index: 1;
    transition: transform 0.15s;
}

.step-label {
    font-size: 0.75rem;
    white-space: nowrap;
}

/* States */
.step-item.active .step-icon {
    background: #0d6efd;
    color: white;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-icon {
    background: #198754;
    color: white;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.pending .step-icon {
    background: #dee2e6;
    color: #6c757d;
}

.step-item.pending .step-label {
    color: #adb5bd;
}

